class Solution {
public:
    long long repairCars(vector<int>& ranks, int cars) {
        sort(ranks.begin(), ranks.end());
        long long low = 0, high = 1e14;
        while (low < high) {
            long long mid = low + (high - low) / 2;
            long long total = 0;
            for (int rank : ranks) {
                total += mid / (rank * 2);
            }
            if (total >= cars) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }
};

